_legacy_cleanup_notice_emitted = False


def _installed_cli_version() -> str:
    from importlib.metadata import PackageNotFoundError, version

    try:
        return version("zhanla")
    except PackageNotFoundError:
        return "unknown"


def _version_callback(value: bool) -> None:
    if not value:
        return
    typer.echo(_installed_cli_version())
    raise typer.Exit()


@app.callback()
def main(
    version: bool = typer.Option(
        False,
        "--version",
        callback=_version_callback,
        is_eager=True,
        help="Show the installed CLI version and exit.",
    ),
) -> None:
    pass

from zhanla_cli.state import cleanup_legacy_state
from zhanla_cli.version_check import start_version_check


def _announce_legacy_cleanup_if_needed(cleanup_happened: bool) -> None:
    global _legacy_cleanup_notice_emitted
    if not cleanup_happened or _legacy_cleanup_notice_emitted:
        return
    _legacy_cleanup_notice_emitted = True
    console.print(
        "[yellow]Removed legacy `.benchmark` CLI state.[/yellow] "
        "This CLI now stores repo-local state in `.zhanla`. "
        "Run `zhanla login` in this repo if you need access."
    )


_announce_legacy_cleanup_if_needed(cleanup_legacy_state())
start_version_check()

# Load .env / .env.local so API keys are available to both Python and TypeScript components.
