if _dotenv_path is not None:
    console.print(f"[dim]Loaded env from {_dotenv_path}[/dim]")

DEFAULT_BASE_URL = "https://benchmark-black.vercel.app"


def _get_base_url() -> str:
    return DEFAULT_BASE_URL


def _infer_runtime_providers(results: list[object]) -> list[str]:
    providers: list[str] = []
    for result in results:
        llm_calls = None
        if isinstance(result, dict):
            llm_calls = result.get("component_llm_calls") or result.get("componentLlmCalls")
        else:
            llm_calls = getattr(result, "component_llm_calls", None) or getattr(result, "componentLlmCalls", None)
        if not isinstance(llm_calls, list):
            continue
        for call in llm_calls:
            provider = call.get("provider") if isinstance(call, dict) else getattr(call, "provider", None)
            if isinstance(provider, str) and provider and provider not in providers:
                providers.append(provider)
    return providers


def _infer_pre_run_provider(model: str | None) -> str | None:
    """Derive the provider for the pre-run config table.

    Checks ZHANLA_EXAMPLE_PROVIDER first; falls back to pattern-matching the
    model string for well-known prefixes.
    """
    import os, re
    env = os.environ.get("ZHANLA_EXAMPLE_PROVIDER", "").strip().lower()
    if env:
        return env
    if not model:
        return None
    m = model.lower()
    if m.startswith("claude-"):
        return "anthropic"
    if m.startswith("gemini-"):
        return "gemini"
    if re.match(r"^(gpt-|o1-|o3-|o4-)", m):
        return "openai"
    # OpenRouter models are typically in "provider/model" format (e.g. "openai/gpt-4.1-mini")
    if "/" in m:
        return "openrouter"
    return None


def _infer_runtime_model_choice(results: list[object]) -> str | None:
    models: list[str] = []
    for result in results:
        llm_calls = None
        if isinstance(result, dict):
            llm_calls = result.get("component_llm_calls")
            if llm_calls is None:
                llm_calls = result.get("componentLlmCalls")
        else:
            llm_calls = getattr(result, "component_llm_calls", None)
            if llm_calls is None:
                llm_calls = getattr(result, "componentLlmCalls", None)
        if not isinstance(llm_calls, list):
            continue
        for call in llm_calls:
            model = call.get("model") if isinstance(call, dict) else getattr(call, "model", None)
            if not isinstance(model, str):
                continue
            normalized = model.strip()
            if normalized and normalized not in models:
                models.append(normalized)
    if len(models) == 1:
        return models[0]
    return None


def _update_progress_task(
    progress,
    task_id,
    *,
    phase: str,
    status: str,
    total: int,
    completed: int = 0,
) -> None:
    safe_total = max(int(total or 0), 1)
    safe_completed = min(max(int(completed or 0), 0), safe_total)
    progress.update(
        task_id,
        total=safe_total,
        completed=safe_completed,
        phase=phase,
        status=status,
    )


def _managed_eval_status_text(run_status: dict, *, items_completed: int, items_total: int) -> str:
    status = str(run_status.get("status", "unknown"))
    error = run_status.get("error")

    if status == "pending":
        return "queued"
    if status in {"running", "completed"}:
        return f"{items_completed}/{items_total} items"
    if status == "failed":
        return str(error) if error else "failed"
    if items_total > 0:
        return f"{status} {items_completed}/{items_total} items"
    return status


def _make_managed_eval_progress_callback(
    progress,
    task_id,
    *,
    expected_total: int,
    completed_offset: int = 0,
    total_offset: int = 0,
):
    def _callback(run_status: dict) -> None:
        items_total = int(run_status.get("items_total") or expected_total or 0)
        if items_total <= 0:
            items_total = max(expected_total, 1)
        items_completed = int(run_status.get("items_completed") or 0)
        _update_progress_task(
            progress,
            task_id,
            phase="Trigger.dev evaluation",
            status=_managed_eval_status_text(
                run_status,
                items_completed=items_completed,
                items_total=items_total,
            ),
            total=total_offset + items_total,
            completed=completed_offset + items_completed,
        )

    return _callback


def _parse_target(spec: str) -> tuple[str, str | None]:
    if ":" in spec:
        filepath, name = spec.rsplit(":", 1)
        if not name:
            raise ValueError(f"Empty component key in target: {spec!r}")
        return filepath, name
    return spec, None


def _is_missing_python_sdk(exc: ModuleNotFoundError) -> bool:
    missing = exc.name or ""
    return missing == "zhanla" or missing.startswith("zhanla.")


def _exit_missing_python_sdk() -> None:
    typer.echo(
        "Python local execution requires zhanla-sdk-py. "
        "Install it with `pip install zhanla-sdk-py`.",
        err=True,
    )
    raise typer.Exit(1)


# ---------------------------------------------------------------------------
# zhanla login
# ---------------------------------------------------------------------------

@app.command()
def login() -> None:
    """Authenticate with your SDK API key."""
    from zhanla_cli.auth import exchange_key_for_token, get_credentials_path, save_credentials

    composite_key = typer.prompt("Enter your SDK API key", hide_input=True)

    if "." not in composite_key:
        typer.echo("Invalid key format. Expected: bm_kid_XXXX.bm_sec_XXXX", err=True)
        raise typer.Exit(1)

    key_id, secret = composite_key.split(".", 1)
    base_url = _get_base_url()

    try:
        token_data = exchange_key_for_token(key_id, secret, base_url)
    except Exception as e:
        typer.echo(f"Login failed: {e}", err=True)
        raise typer.Exit(1)

    creds: dict = {
        "key_id": key_id,
        "secret": secret,
        "supabase_url": token_data["supabase_url"],
        "supabase_anon_key": token_data["supabase_anon_key"],
        "org_id": token_data["org_id"],
    }
    org_name = token_data.get("org_name")
    if org_name:
        creds["org_name"] = org_name
    save_credentials(creds)
    org_display = org_name or token_data["org_id"]
    typer.echo(
        f"Logged in successfully as {org_display}. "
        f"Credentials saved to {get_credentials_path()}. "
        "This login is only used from this repo."
    )


# ---------------------------------------------------------------------------
# zhanla logout
# ---------------------------------------------------------------------------

@app.command()
def logout() -> None:
    """Remove saved credentials."""
    from zhanla_cli.auth import delete_credentials, get_credentials_path
    delete_credentials()
    typer.echo(f"Logged out. Removed repo credentials from {get_credentials_path()}.")


# ---------------------------------------------------------------------------
# zhanla run
# ---------------------------------------------------------------------------

@app.command()
def run(
    target: Optional[str] = typer.Argument(
        None,
        help="component.py:key — file path and component key",
    ),
    eval_target: Optional[str] = typer.Option(
        None, "--eval", "-e",
        help="eval.py:key — file path and eval key",
    ),
    dataset: Optional[str] = typer.Option(
        None, "--dataset", "-d",
        help="Path to dataset file (.json or .csv)",
    ),
    web_eval: Optional[str] = typer.Option(
        None, "--web-eval",
        help="Autorater key for a managed web evaluation run",
    ),
    web_dataset: Optional[str] = typer.Option(
        None, "--web-dataset",
        help="Dataset key to fetch from the web app before local execution",
    ),
    web_config: Optional[str] = typer.Option(
        None, "--web-config",
        help="Component key for a fully web-backed run",
    ),
    output: Optional[str] = typer.Option(
        None, "--output", "-o",
        help="Write machine-readable per-item results to this JSON file path",
    ),
    dry_run: bool = typer.Option(False, "--dry-run", help="Validate and execute locally, skip sync/upload"),
    fail_on_row_error: bool = typer.Option(
        False,
        "--fail-on-row-error",
        help="Exit non-zero when any dataset row has component or eval execution errors.",
    ),
    yes: bool = typer.Option(False, "--yes", "-y", help="Skip the pre-run confirmation prompt."),
    max_rows: Optional[int] = typer.Option(
        None, "--max-rows",
        help="Limit the number of dataset rows to run (e.g. --max-rows 10 runs only the first 10 rows).",
    ),
) -> None:
    """Run a component against a dataset and score with an eval.

    All three arguments are required:
      zhanla run <component> --dataset <file> --eval <evaluator>
    """
    from zhanla_cli.data_utils import load_dataset, validate_output_schema
    from zhanla_cli.evaluations import poll_evaluation, start_evaluation
    from zhanla_cli.manifest import validate_manifest
    from zhanla_cli.runners import (
        NodeRunner,
        RunnerError,
        detect_language,
        validate_same_language,
        discover_ts_components,
        discover_python_components,
        check_required_api_keys,
    )
    from zhanla_cli.ui import (
        print_remote_evaluation_summary,
        print_run_config,
        print_score_summary,
        create_progress,
    )
    from zhanla_cli.web import (
        derive_expected_output,
        derive_model_input,
        derive_model_response,
        fetch_web_dataset,
        fetch_web_prompt,
        resolve_web_autorater,
        start_evaluate_only,
    )

    base_url = _get_base_url()
    trigger_run_id = str(uuid.uuid4())

    if bool(target) == bool(web_config):
        typer.echo(
            "Provide exactly one component source: local target or --web-config.",
            err=True,
        )
        raise typer.Exit(1)

    if bool(dataset) == bool(web_dataset):
        typer.echo(
            "Provide exactly one dataset source: --dataset or --web-dataset.",
            err=True,
        )
        raise typer.Exit(1)

    if bool(eval_target) and bool(web_eval):
        typer.echo(
            "Provide exactly one evaluation source: --eval or --web-eval.",
            err=True,
        )
        raise typer.Exit(1)

    if web_config and (target or eval_target or dataset):
        typer.echo(
            "--web-config is only supported for the fully web-backed flow "
            "(--web-config + --web-dataset + --web-eval).",
            err=True,
        )
        raise typer.Exit(1)

    if web_config and dry_run:
        typer.echo("Dry run is not supported for fully web-backed runs.", err=True)
        raise typer.Exit(1)

    if web_config and not (web_dataset and web_eval):
        typer.echo(
            "--web-config requires --web-dataset and --web-eval.",
            err=True,
        )
        raise typer.Exit(1)

    if dry_run and web_eval:
        typer.echo("Dry run is not supported with --web-eval.", err=True)
        raise typer.Exit(1)

    token_data: dict | None = None

    component = None
    eval_component = None
    component_manifest = None
    eval_manifest = None
    ts_manifests: dict[str, object] = {}
    component_lang: str | None = None
    eval_lang: str | None = None
    closure_manifests: list | None = None  # full transitive closure for upload

    # --- Discover component ---
    if target:
        target_filepath, target_key = _parse_target(target)

        try:
            component_lang = detect_language(target_filepath)
        except ValueError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

        if component_lang == "typescript":
            # TypeScript path: discover via npx zhanla-sdk-ts
            ts_spec = f"{target_filepath}:{target_key}" if target_key else target_filepath
            try:
                discovered_ts_manifests = discover_ts_components(ts_spec)
            except RunnerError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)
            except ValueError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)

            # The closure is leaf-first; root (target) is the last element.
            closure_manifests = discovered_ts_manifests
            for manifest in closure_manifests:
                ts_manifests[manifest.name] = manifest

            runnable = [m for m in closure_manifests if m.is_runnable]

            if target_key is not None:
                matches = [m for m in runnable if m.key == target_key]
                if not matches:
                    eval_matches = [m for m in closure_manifests if m.is_eval and m.key == target_key]
                    if eval_matches:
                        typer.echo(
                            f"'{target_key}' is an eval component key. Use --eval to reference it.",
                            err=True,
                        )
                    else:
                        name_matches = [m for m in runnable if m.name == target_key]
                        if name_matches:
                            available_keys = ", ".join(m.key for m in name_matches)
                            typer.echo(
                                f"Component '{target_key}' matched a component name, but local CLI targets now use component keys. "
                                f"Use one of: {available_keys}",
                                err=True,
                            )
                            raise typer.Exit(1)
                        available = ", ".join(m.key for m in runnable)
                        typer.echo(
                            f"Component key '{target_key}' not found in {target_filepath}. "
                            f"Available keys: {available}",
                            err=True,
                        )
                    raise typer.Exit(1)
                component_manifest = matches[0]
            elif len(runnable) == 1:
                component_manifest = runnable[0]
            elif len(runnable) == 0:
                typer.echo(f"No runnable components found in {target_filepath}", err=True)
                raise typer.Exit(1)
            else:
                keys = ", ".join(m.key for m in runnable)
                typer.echo(
                    f"Multiple runnable components in {target_filepath}: {keys}. "
                    f"Specify which one with file.ts:component_key",
                    err=True,
                )
                raise typer.Exit(1)

            # Validate manifest
            from zhanla_cli.manifest import validate_manifest
            manifest_errors = validate_manifest(component_manifest)
            if manifest_errors:
                for err in manifest_errors:
                    typer.echo(f"ERROR: {err}", err=True)
                raise typer.Exit(1)

            typer.echo(f"Component: {component_manifest.name} (TypeScript)")

        else:
            # Python path: discover live object for execution, closure manifests for upload
            try:
                from zhanla_cli.discovery import (
                    discover_targeted_component,
                    validate_component,
                )
            except ModuleNotFoundError as exc:
                if _is_missing_python_sdk(exc):
                    _exit_missing_python_sdk()
                raise
            try:
                component, _ = discover_targeted_component(target)
            except ValueError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)

            comp_errors = validate_component(component)
            if comp_errors:
                for err in comp_errors:
                    typer.echo(f"ERROR: {err}", err=True)
                raise typer.Exit(1)

            try:
                closure_manifests = discover_python_components(target)
            except ValueError as e:
                typer.echo(f"Closure discovery failed: {e}", err=True)
                raise typer.Exit(1)

    # --- Discover eval ---
    if eval_target:
        eval_filepath, _ = _parse_target(eval_target)

        try:
            eval_lang = detect_language(eval_filepath)
        except ValueError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

        # Same-language validation
        try:
            validate_same_language(component_lang or "python", eval_lang)
        except ValueError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

        if eval_lang == "typescript":
            try:
                ts_eval_manifests = discover_ts_components(eval_filepath)
            except RunnerError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)
            except ValueError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)

            for manifest in ts_eval_manifests:
                ts_manifests[manifest.name] = manifest

            eval_manifests_list = [m for m in ts_eval_manifests if m.is_eval]
            _, eval_key = _parse_target(eval_target)

            if eval_key is not None:
                matches = [m for m in eval_manifests_list if m.key == eval_key]
                if not matches:
                    name_matches = [m for m in eval_manifests_list if m.name == eval_key]
                    if name_matches:
                        available_keys = ", ".join(m.key for m in name_matches)
                        typer.echo(
                            f"Eval '{eval_key}' matched an eval name, but local CLI targets now use eval keys. "
                            f"Use one of: {available_keys}",
                            err=True,
                        )
                        raise typer.Exit(1)
                    available = ", ".join(m.key for m in eval_manifests_list)
                    typer.echo(
                        f"Eval key '{eval_key}' not found in {eval_filepath}. Available keys: {available}",
                        err=True,
                    )
                    raise typer.Exit(1)
                eval_manifest = matches[0]
            elif len(eval_manifests_list) == 1:
                eval_manifest = eval_manifests_list[0]
            elif len(eval_manifests_list) == 0:
                typer.echo(f"No eval components found in {eval_filepath}", err=True)
                raise typer.Exit(1)
            else:
                keys = ", ".join(m.key for m in eval_manifests_list)
                typer.echo(
                    f"Multiple evals in {eval_filepath}: {keys}. "
                    f"Specify which one with file.ts:eval_key",
                    err=True,
                )
                raise typer.Exit(1)

        else:
            try:
                from zhanla_cli.discovery import discover_eval, validate_component
            except ModuleNotFoundError as exc:
                if _is_missing_python_sdk(exc):
                    _exit_missing_python_sdk()
                raise
            try:
                eval_component = discover_eval(eval_target)
            except ValueError as e:
                typer.echo(str(e), err=True)
                raise typer.Exit(1)

            eval_errors = validate_component(eval_component)
            if eval_errors:
                for err in eval_errors:
                    typer.echo(f"ERROR: {err}", err=True)
                raise typer.Exit(1)

    elif web_eval:
        typer.echo(f"Web autorater: {web_eval}")

    # --- Auth check ---
    requires_auth = (not dry_run) or bool(web_dataset) or bool(web_eval) or bool(web_config)
    if requires_auth:
        token_data = _require_token(base_url)

    use_managed_eval_for_local = bool(eval_target) and not dry_run
    resolved_web_autorater = None
    if web_eval:
        assert token_data is not None
        try:
            resolved_web_autorater = resolve_web_autorater(
                supabase_url=token_data["supabase_url"],
                supabase_anon_key=token_data["supabase_anon_key"],
                access_token=token_data["access_token"],
                autorater_key_or_id=web_eval,
            )
        except Exception as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

    if web_config:
        assert token_data is not None
        prompt = fetch_web_prompt(
            supabase_url=token_data["supabase_url"],
            supabase_anon_key=token_data["supabase_anon_key"],
            access_token=token_data["access_token"],
            prompt_key_or_id=web_config,
        )
        typer.echo(f"Web config: {prompt.get('slug') or web_config}")
        progress = create_progress(transient=True)
        progress.start()
        try:
            task = progress.add_task(
                f"Running {prompt.get('slug') or web_config}",
                total=2,
                completed=0,
                phase="Starting run",
                status="submitting to Trigger.dev",
            )
            # Full managed web flow:
            # 1. server-side component response generation with the user's provider key
            # 2. managed autorater execution on platform infrastructure
            start_result = start_evaluation(
                base_url=base_url,
                access_token=token_data["access_token"],
                autorater_id=resolved_web_autorater.autorater_id if resolved_web_autorater else web_eval,
                dataset_id=web_dataset,
                component_family_id=prompt.get("component_family_id"),
                component_definition_id=prompt.get("id"),
                max_rows=max_rows if max_rows is not None and max_rows > 0 else None,
                org_id=token_data["org_id"],
            )
            resolved_autorater_id = (
                resolved_web_autorater.autorater_id if resolved_web_autorater else web_eval
            )
            result_url = f"{base_url}/autoraters/{resolved_autorater_id}/runs/{start_result['runId']}"
            _update_progress_task(
                progress,
                task,
                phase="Trigger.dev evaluation",
                status="queued",
                total=2,
                completed=1,
            )
            final_status = poll_evaluation(
                base_url=base_url,
                access_token=token_data["access_token"],
                run_id=start_result["runId"],
                org_id=token_data["org_id"],
                progress_callback=_make_managed_eval_progress_callback(
                    progress,
                    task,
                    expected_total=1,
                    completed_offset=1,
                    total_offset=1,
                ),
            )
        finally:
            progress.stop()
        print_remote_evaluation_summary(
            component_name=prompt.get("slug") or web_config,
            run_status=final_status,
            result_url=result_url,
            autorater_id=resolved_autorater_id,
            autorater_run_id=start_result["runId"],
        )
        if output and final_status.get("status") != "failed":
            _write_web_config_output(
                output_path=output,
                run_id=start_result["runId"],
                token_data=token_data,
            )
        if final_status.get("status") == "failed":
            raise typer.Exit(1)
        return

    # For TS components, we have a manifest but no live object.
    # For Python components, we have a live object.
    is_ts_run = component_lang == "typescript" and component_manifest is not None

    if not is_ts_run:
        assert component is not None

    # --- API key pre-flight check ---
    _preflight_models: set[str] = set()
    if component_manifest is not None and component_manifest.model:
        _preflight_models.add(component_manifest.model)
    if component is not None:
        _m = getattr(component, "model", None)
        if _m:
            _preflight_models.add(_m)
    if eval_manifest is not None and eval_manifest.model:
        _preflight_models.add(eval_manifest.model)
    if eval_component is not None:
        _m = getattr(eval_component, "model", None)
        if _m:
            _preflight_models.add(_m)

    if _preflight_models:
        _api_key_errors = check_required_api_keys(_preflight_models)
        if _api_key_errors:
            for _err in _api_key_errors:
                typer.echo(f"ERROR: {_err}", err=True)
            raise typer.Exit(1)

    # --- Load dataset ---
    try:
        if dataset:
            dataset_rows, dataset_config = load_dataset(dataset)
            dataset_name = Path(dataset).stem
            dataset_id = None
            dataset_item_ids = None
            dataset_input_columns = (
                dataset_config.get("schema")
                if isinstance(dataset_config, dict) and isinstance(dataset_config.get("schema"), dict)
                else None
            )
        else:
            assert token_data is not None
            web_dataset_result = fetch_web_dataset(
                supabase_url=token_data["supabase_url"],
                supabase_anon_key=token_data["supabase_anon_key"],
                access_token=token_data["access_token"],
                dataset_key_or_id=web_dataset or "",
            )
            dataset_rows = web_dataset_result.rows
            dataset_config = None
            dataset_name = web_dataset_result.dataset_name
            dataset_id = web_dataset_result.dataset_id
            dataset_item_ids = web_dataset_result.item_ids
            dataset_input_columns = None
    except Exception as e:
        typer.echo(str(e), err=True)
        raise typer.Exit(1)

    if not dataset_rows:
        typer.echo("Dataset is empty.", err=True)
        raise typer.Exit(1)

    if max_rows is not None and max_rows > 0:
        dataset_rows = dataset_rows[:max_rows]
        if dataset_item_ids is not None:
            dataset_item_ids = dataset_item_ids[:max_rows]

    # --- Pre-run confirmation ---
    _conf_name = component_manifest.name if is_ts_run else component.name
    _conf_type = component_manifest.component_type if is_ts_run else getattr(component.component_type, "value", str(component.component_type))
    _conf_model = component_manifest.model if is_ts_run else getattr(component, "model", None)
    _conf_eval = (
        (eval_manifest.name if eval_manifest else None)
        or (eval_component.name if eval_component else None)
        or (resolved_web_autorater.autorater_key if resolved_web_autorater else web_eval)
    )
    print_run_config(
        component_name=_conf_name,
        component_type=_conf_type,
        model=_conf_model,
        provider=_infer_pre_run_provider(_conf_model),
        eval_name=_conf_eval,
        dataset_name=dataset_name,
        row_count=len(dataset_rows),
        dry_run=dry_run,
    )
    if not yes:
        if not typer.confirm("Proceed with run?", default=False):
            raise typer.Exit(0)

    # --- Execute with progress bar ---
    results: list = []
    output_schema = component_manifest.output_schema if is_ts_run else getattr(component, "output_schema", None)
    managed_eval_progress = bool(web_eval or use_managed_eval_for_local)
    progress_label = component_manifest.name if is_ts_run else component.name
    local_progress_total = len(dataset_rows)
    upload_progress_total = 0 if dry_run else 1
    managed_eval_item_total = len(dataset_rows) if managed_eval_progress and not dry_run else 0
    overall_progress_total = (
        local_progress_total + upload_progress_total + managed_eval_item_total
    )

    # --- Upload ---
    upload_failed = False
    upload_error: str | None = None
    result_url: str | None = None
    autorater_id: str | None = None
    autorater_run_id: str | None = None
    upload_started_at: str | None = None
    upload_completed_at: str | None = None
    _pending_remote_eval_summary: dict | None = None

    if is_ts_run:
        # TypeScript path: start NodeRunner subprocess, stream rows
        assert component_manifest is not None
        node_runner = NodeRunner(
            manifest=component_manifest,
            eval_manifest=None if use_managed_eval_for_local else eval_manifest,
            file_path=component_manifest.file_path or "",
        )
        try:
            node_runner.start()
        except RunnerError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

    else:
        try:
            from zhanla_cli.executor import execute_row
        except ModuleNotFoundError as exc:
            if _is_missing_python_sdk(exc):
                _exit_missing_python_sdk()
            raise

    progress = create_progress(transient=managed_eval_progress)
    progress.start()
    try:
        task = progress.add_task(
            f"Running {progress_label}",
            total=overall_progress_total,
            completed=0,
            phase="Local component run",
            status="starting",
        )

        if is_ts_run:
            try:
                async def run_ts_with_progress():
                    out = []
                    for i, row in enumerate(dataset_rows):
                        progress.update(
                            task,
                            phase="Local component run",
                            status=f"row {i + 1}/{len(dataset_rows)}",
                        )
                        row_result = await node_runner.run_row(row, trigger_run_id)
                        out.append(row_result)

                        if (
                            i == 0
                            and output_schema
                            and row_result.get("output")
                            and "_component_error" not in row_result["output"]
                        ):
                            schema_error = validate_output_schema(
                                row_result["output"], output_schema, component_manifest.name
                            )
                            if schema_error:
                                progress.update(
                                    task,
                                    phase="Local component run",
                                    status="schema error",
                                )
                                raise ValueError(schema_error)

                        progress.advance(task)
                    progress.update(task, phase="Local component run", status="done")
                    return out

                try:
                    results = asyncio.run(run_ts_with_progress())
                except ValueError as e:
                    progress.stop()
                    console.print(f"[bold red]Error:[/bold red] {e}")
                    raise typer.Exit(1)
            finally:
                node_runner.stop()

        # Python path
        else:
            async def run_with_progress():
                out = []
                for i, row in enumerate(dataset_rows):
                    progress.update(
                        task,
                        phase="Local component run",
                        status=f"row {i + 1}/{len(dataset_rows)}",
                    )
                    result = await execute_row(
                        component,
                        None if use_managed_eval_for_local else eval_component,
                        row,
                        trigger_run_id,
                    )
                    out.append(result)

                    # First-row fail-fast output validation
                    if (
                        i == 0
                        and output_schema
                        and result.component_trace.output
                        and "_component_error" not in result.component_trace.output
                    ):
                        schema_error = validate_output_schema(
                            result.component_trace.output, output_schema, component.name
                        )
                        if schema_error:
                            progress.update(
                                task,
                                phase="Local component run",
                                status="schema error",
                            )
                            raise ValueError(schema_error)

                    progress.advance(task)
                progress.update(task, phase="Local component run", status="done")
                return out

            try:
                results = asyncio.run(run_with_progress())
            except ValueError as e:
                progress.stop()
                console.print(f"[bold red]Error:[/bold red] {e}")
                raise typer.Exit(1)

        if is_ts_run:
            from zhanla_cli.ts_adapter import build_manifest_component, ts_result_to_traces

            component = build_manifest_component(component_manifest, list(ts_manifests.values()))
            built_eval_component = (
                build_manifest_component(eval_manifest, list(ts_manifests.values()))
                if eval_manifest is not None
                else None
            )
            eval_component = built_eval_component
            converted = [
                ts_result_to_traces(
                    row=row,
                    row_result=row_result,
                    component=component,
                    eval_component=(
                        None if use_managed_eval_for_local else built_eval_component
                    ),
                    trigger_run_id=trigger_run_id,
                )
                for row, row_result in zip(dataset_rows, results)
            ]
            component_traces = [component_trace for component_trace, _ in converted]
            eval_traces = [eval_trace for _, eval_trace in converted]
        else:
            component_traces = [r.component_trace for r in results]
            eval_traces = [r.eval_trace for r in results]

        if not dry_run:
            upload_started_at = datetime.now().astimezone().isoformat(timespec="seconds")
            _update_progress_task(
                progress,
                task,
                phase="Uploading results",
                status="syncing traces",
                total=overall_progress_total,
                completed=local_progress_total,
            )
            try:
                from zhanla_cli.writer import infer_run_model_choice, write_run_results
                assert token_data is not None
                runtime_model_endpoint = _infer_runtime_model_choice(results)
                local_model_endpoint = runtime_model_endpoint or infer_run_model_choice(
                    component,
                    closure_manifests,
                )

                upload_result = write_run_results(
                    component=component,
                    eval_component=eval_component or component,
                    component_traces=component_traces,
                    eval_traces=eval_traces,
                    supabase_url=token_data["supabase_url"],
                    supabase_anon_key=token_data["supabase_anon_key"],
                    access_token=token_data["access_token"],
                    org_id=token_data["org_id"],
                    closure=closure_manifests,
                    dataset_id=dataset_id,
                    dataset_item_ids=dataset_item_ids,
                    dataset_name=dataset_name,
                    dataset_rows=dataset_rows if dataset_id is None else None,
                    dataset_input_columns=dataset_input_columns if dataset_id is None else None,
                    sync_managed_eval_only=use_managed_eval_for_local,
                    component_model_choice=local_model_endpoint,
                    base_url=base_url,
                )
                _update_progress_task(
                    progress,
                    task,
                    phase="Uploading results",
                    status="uploaded",
                    total=overall_progress_total,
                    completed=local_progress_total + upload_progress_total,
                )
                if web_eval or use_managed_eval_for_local:
                    if upload_result is None:
                        raise RuntimeError("Upload did not return managed evaluation metadata")
                    if not upload_result.dataset_id or not upload_result.dataset_item_ids:
                        raise RuntimeError("Dataset upload did not return dataset item IDs")
                    remote_autorater_id = (
                        resolved_web_autorater.autorater_id
                        if resolved_web_autorater
                        else upload_result.autorater_id
                    )
                    if not remote_autorater_id:
                        raise RuntimeError("Eval sync did not return an autorater ID")

                    items = []
                    for item_id, row, component_trace in zip(upload_result.dataset_item_ids, dataset_rows, component_traces):
                        items.append(
                            {
                                "itemId": item_id,
                                "modelInput": derive_model_input(row),
                                "modelResponse": derive_model_response(
                                    component_trace.output
                                ),
                                "expectedOutput": derive_expected_output(row),
                                "pathTaken": component_trace.path_taken,
                            }
                        )

                    _update_progress_task(
                        progress,
                        task,
                        phase="Trigger.dev evaluation",
                        status="submitting run",
                        total=overall_progress_total,
                        completed=local_progress_total + upload_progress_total,
                    )

                    # Local component + managed autorater flow:
                    # 1. component response already computed locally
                    # 2. server runs only the managed autorater over uploaded responses
                    start_result = start_evaluate_only(
                        base_url=base_url,
                        access_token=token_data["access_token"],
                        autorater_id=remote_autorater_id,
                        items=items,
                        dataset_id=upload_result.dataset_id,
                        model_endpoint=local_model_endpoint,
                        org_id=token_data["org_id"],
                    )
                    autorater_id = remote_autorater_id
                    autorater_run_id = start_result["runId"]
                    result_url = (
                        f"{base_url}/autoraters/{remote_autorater_id}/runs/{start_result['runId']}"
                    )
                    final_status = poll_evaluation(
                        base_url=base_url,
                        access_token=token_data["access_token"],
                        run_id=start_result["runId"],
                        org_id=token_data["org_id"],
                        progress_callback=_make_managed_eval_progress_callback(
                            progress,
                            task,
                            expected_total=max(len(items), 1),
                            completed_offset=local_progress_total + upload_progress_total,
                            total_offset=local_progress_total + upload_progress_total,
                        ),
                    )
                    upload_completed_at = datetime.now().astimezone().isoformat(timespec="seconds")
                    _pending_remote_eval_summary = {
                        "component_name": component.name,
                        "run_status": final_status,
                        "result_url": result_url,
                        "autorater_id": autorater_id,
                        "autorater_run_id": autorater_run_id,
                        "upload_started_at": upload_started_at,
                        "upload_completed_at": upload_completed_at,
                    }
                elif upload_result is not None:
                    autorater_id = upload_result.autorater_id
                    autorater_run_id = upload_result.autorater_run_id
                    if upload_result.autorater_id and upload_result.autorater_run_id:
                        result_url = (
                            f"{base_url}/autoraters/{upload_result.autorater_id}"
                            f"/runs/{upload_result.autorater_run_id}"
                        )
                if upload_completed_at is None:
                    upload_completed_at = datetime.now().astimezone().isoformat(timespec="seconds")
            except Exception as e:
                upload_completed_at = datetime.now().astimezone().isoformat(timespec="seconds")
                _update_progress_task(
                    progress,
                    task,
                    phase="Upload failed",
                    status=str(e)[:80],
                    total=overall_progress_total,
                    completed=local_progress_total,
                )
                upload_error = str(e)
                upload_failed = True
    finally:
        progress.stop()

    # --- Print deferred summaries (always after progress bar clears) ---
    if upload_error:
        console.print(f"[bold red]Upload failed:[/bold red] {upload_error}")
    if _pending_remote_eval_summary is not None:
        print_remote_evaluation_summary(**_pending_remote_eval_summary)
        if (_pending_remote_eval_summary.get("run_status") or {}).get("status") == "failed":
            _eval_err = (_pending_remote_eval_summary.get("run_status") or {}).get("error") or "Remote evaluation failed"
            console.print(f"[bold red]Remote evaluation failed:[/bold red] {_eval_err}")
            raise typer.Exit(1)

    # --- Print summary ---
    if not web_eval and not use_managed_eval_for_local:
        print_score_summary(
            component_traces=component_traces,
            eval_traces=eval_traces,
            component_name=component.name,
            dry_run=dry_run,
            uploaded=not upload_failed,
            result_url=result_url,
            autorater_id=autorater_id,
            autorater_run_id=autorater_run_id,
            upload_started_at=upload_started_at,
            upload_completed_at=upload_completed_at,
        )
        if output:
            from zhanla_cli.eval_contract import (
                derive_model_input as _dmi,
                derive_model_response as _dmr,
                derive_expected_output as _deo,
            )
            import json
            items_out = []
            local_scores: list[float] = []
            for i, (comp_trace, eval_trace) in enumerate(zip(component_traces, eval_traces)):
                row = dataset_rows[i] if i < len(dataset_rows) else {}
                item_id = (dataset_item_ids[i] if dataset_item_ids and i < len(dataset_item_ids) else None) or str(i)
                _model_input = _dmi(row) if isinstance(row, dict) else str(row)
                _model_response = _dmr(comp_trace.output) if comp_trace and comp_trace.output else ""
                _expected_output = _deo(row) if isinstance(row, dict) else ""
                score = None
                reason = ""
                if eval_trace and eval_trace.output and isinstance(eval_trace.output, dict):
                    score = eval_trace.output.get("score")
                    reason = str(eval_trace.output.get("reason") or eval_trace.output.get("reasoning") or "")
                if score is not None:
                    local_scores.append(float(score))
                items_out.append({
                    "item_id": item_id,
                    "model_input": _model_input,
                    "model_response": _model_response,
                    "expected_output": _expected_output,
                    "score": score,
                    "reason": reason or (f"{float(score):.4f}" if score is not None else ""),
                })
            mean_score = sum(local_scores) / len(local_scores) if local_scores else 0.0
            output_data = {"mean_score": mean_score, "run_id": trigger_run_id, "items": items_out}
            Path(output).write_text(json.dumps(output_data, indent=2, ensure_ascii=False))
            typer.echo(f"Results written to {output}")

    component_failed_count = sum(1 for trace in component_traces if trace.status == "failed")
    eval_failed_count = sum(1 for trace in eval_traces if trace is not None and trace.status == "failed")

    if fail_on_row_error and (component_failed_count > 0 or eval_failed_count > 0):
        typer.echo(
            (
                "Run failed due to row execution errors: "
                f"{component_failed_count} component row(s), {eval_failed_count} eval row(s)."
            ),
            err=True,
        )
        raise typer.Exit(1)

    if upload_failed:
        raise typer.Exit(1)


# ---------------------------------------------------------------------------
# zhanla list datasets / zhanla list autoraters
# ---------------------------------------------------------------------------

OWNER_TYPES = ["agent", "skill", "tool", "orchestration"]
OWNER_TABLES = {
    "agent": "agents",
    "skill": "skills",
    "tool": "tools",
    "orchestration": "orchestrations",
}


def _require_token(base_url: str) -> dict:
    global _saved_login_notice_emitted
    from zhanla_cli.auth import get_credentials_path, get_fresh_token

    try:
        token_data = get_fresh_token(base_url)
    except RuntimeError as exc:
        typer.echo(str(exc), err=True)
        raise typer.Exit(1) from exc
    if not _saved_login_notice_emitted:
        org_name = token_data.get("org_name")
        org_id = token_data.get("org_id")
        org_display = org_name or org_id
        org_suffix = f" for {org_display}" if org_display else ""
        typer.echo(
            "Using repo login"
            f"{org_suffix} from {get_credentials_path()}. "
            "Run `zhanla logout` to clear it for this repo.",
            err=True,
        )
        _saved_login_notice_emitted = True
    return token_data


def _owner_belongs_to_org(client, *, owner_id: str, owner_type: str, org_id: str) -> bool:
    table_name = OWNER_TABLES.get(owner_type)
    if table_name is None:
        return False
    try:
        result = (
            client.table(table_name)
            .select("id")
            .eq("id", owner_id)
            .eq("organization_id", org_id)
            .limit(1)
            .execute()
        )
    except Exception:
        return False
    rows = getattr(result, "data", None) or []
    return bool(rows)


def _list_datasets_via_supabase(
    *,
    client,
    org_id: str,
    owner_type: str | None,
    owner_id: str | None,
    name: str | None,
) -> list[dict]:
    if owner_type or owner_id:
        link_query = client.table("component_datasets").select("dataset_id,owner_id,owner_type")
        if owner_type:
            link_query = link_query.eq("owner_type", owner_type)
        if owner_id:
            link_query = link_query.eq("owner_id", owner_id)
        link_rows = getattr(link_query.execute(), "data", None) or []
        dataset_ids = sorted({
            row.get("dataset_id")
            for row in link_rows
            if isinstance(row.get("dataset_id"), str)
            and isinstance(row.get("owner_id"), str)
            and isinstance(row.get("owner_type"), str)
            and _owner_belongs_to_org(
                client,
                owner_id=row["owner_id"],
                owner_type=row["owner_type"],
                org_id=org_id,
            )
        })
        if not dataset_ids:
            return []
        query = (
            client.table("datasets")
            .select("id,key,name,description,input_columns,created_at,deleted_at")
            .eq("organization_id", org_id)
            .in_("id", dataset_ids)
            .order("created_at", desc=True)
        )
    else:
        query = (
            client.table("datasets")
            .select("id,key,name,description,input_columns,created_at,deleted_at")
            .eq("organization_id", org_id)
            .order("created_at", desc=True)
        )

    if name:
        query = query.ilike("name", f"%{name}%")

    rows = getattr(query.execute(), "data", None) or []
    return [row for row in rows if row.get("deleted_at") is None]


def _list_autoraters_via_supabase(
    *,
    client,
    org_id: str,
    owner_type: str | None,
    owner_id: str | None,
    name: str | None,
) -> list[dict]:
    query = (
        client.table("autoraters")
        .select("id,key,name,description,mode,owner_id,owner_type,created_at")
        .eq("organization_id", org_id)
        .order("created_at", desc=True)
    )
    if owner_type:
        query = query.eq("owner_type", owner_type)
    if owner_id:
        query = query.eq("owner_id", owner_id)
    if name:
        query = query.ilike("name", f"%{name}%")

    rows = getattr(query.execute(), "data", None) or []
    return list(rows)


@list_app.callback()
def list_resources(ctx: typer.Context) -> None:
    """List available web resources."""
    if ctx.invoked_subcommand is None:
        typer.echo(ctx.get_help())
        raise typer.Exit()


@list_app.command("datasets")
def list_datasets(
    owner_type: Optional[str] = typer.Option(
        None, "--component-type", "-t",
        help=f"Filter by component type: {', '.join(OWNER_TYPES)}",
    ),
    owner_id: Optional[str] = typer.Option(None, "--component-id", "-c", help="Filter by component ID"),
    name: Optional[str] = typer.Option(None, "--name", "-n", help="Filter by name (case-insensitive substring)"),
) -> None:
    """List datasets available in the web app."""
    from rich.table import Table
    from zhanla_cli.web import (
        SdkListRouteUnavailable,
        list_web_datasets as _list_web_datasets,
    )
    from zhanla_cli.writer import get_supabase_client as _get_client

    if owner_type and owner_type not in OWNER_TYPES:
        typer.echo(f"Invalid --owner-type '{owner_type}'. Choose from: {', '.join(OWNER_TYPES)}", err=True)
        raise typer.Exit(1)

    base_url = _get_base_url()
    token_data = _require_token(base_url)

    client = _get_client(
        token_data["supabase_url"],
        token_data["supabase_anon_key"],
        token_data["access_token"],
    )
    try:
        rows = _list_web_datasets(
            base_url=base_url,
            access_token=token_data["access_token"],
            org_id=token_data.get("org_id"),
            owner_type=owner_type,
            owner_id=owner_id,
            name=name,
        )
    except SdkListRouteUnavailable:
        rows = _list_datasets_via_supabase(
            client=client,
            org_id=token_data["org_id"],
            owner_type=owner_type,
            owner_id=owner_id,
            name=name,
        )

    if not rows:
        typer.echo("No datasets found.")
        return

    table = Table(title="Datasets", show_lines=False)
    table.add_column("Key", style="green", no_wrap=True)
    table.add_column("Name", style="bold")
    table.add_column("ID", style="cyan", no_wrap=True)
    table.add_column("Created", style="dim")

    for row in rows:
        created = (row.get("created_at") or "")[:10]
        table.add_row(row.get("key") or "", row.get("name") or "", row["id"], created)

    console.print(table)
    console.print("[dim]Use --web-dataset <KEY> in `zhanla run`[/dim]")


@list_app.command("autoraters")
def list_autoraters(
    owner_type: Optional[str] = typer.Option(
        None, "--component-type", "-t",
        help=f"Filter by component type: {', '.join(OWNER_TYPES)}",
    ),
    owner_id: Optional[str] = typer.Option(None, "--component-id", "-c", help="Filter by component ID"),
    name: Optional[str] = typer.Option(None, "--name", "-n", help="Filter by name (case-insensitive substring)"),
) -> None:
    """List autoraters available in the web app."""
    from rich.table import Table
    from zhanla_cli.web import (
        SdkListRouteUnavailable,
        list_web_autoraters as _list_web_autoraters,
    )
    from zhanla_cli.writer import get_supabase_client as _get_client

    if owner_type and owner_type not in OWNER_TYPES:
        typer.echo(f"Invalid --owner-type '{owner_type}'. Choose from: {', '.join(OWNER_TYPES)}", err=True)
        raise typer.Exit(1)

    base_url = _get_base_url()
    token_data = _require_token(base_url)

    client = _get_client(
        token_data["supabase_url"],
        token_data["supabase_anon_key"],
        token_data["access_token"],
    )
    try:
        rows = _list_web_autoraters(
            base_url=base_url,
            access_token=token_data["access_token"],
            org_id=token_data.get("org_id"),
            owner_type=owner_type,
            owner_id=owner_id,
            name=name,
        )
    except SdkListRouteUnavailable:
        rows = _list_autoraters_via_supabase(
            client=client,
            org_id=token_data["org_id"],
            owner_type=owner_type,
            owner_id=owner_id,
            name=name,
        )

    if not rows:
        typer.echo("No autoraters found.")
        return

    table = Table(title="Autoraters", show_lines=False)
    table.add_column("Key", style="green", no_wrap=True)
    table.add_column("Name", style="bold")
    table.add_column("ID", style="cyan", no_wrap=True)
    table.add_column("Type", style="magenta")
    table.add_column("Owner ID", style="dim")
    table.add_column("Created", style="dim")

    for row in rows:
        created = (row.get("created_at") or "")[:10]
        table.add_row(
            row.get("key") or "",
            row.get("name") or "",
            row["id"],
            row.get("owner_type") or "",
            row.get("owner_id") or "",
            created,
        )

    console.print(table)
    console.print("[dim]Use --web-eval <KEY> in `zhanla run`[/dim]")


def _write_web_config_output(*, output_path: str, run_id: str, token_data: dict) -> None:
    """Fetch per-item results after a web-config run and write JSON to output_path."""
    import json
    from zhanla_cli.eval_contract import (
        derive_model_input as _dmi,
        derive_expected_output as _deo,
    )
    from zhanla_cli.writer import get_supabase_client as _get_client

    client = _get_client(
        token_data["supabase_url"],
        token_data["supabase_anon_key"],
        token_data["access_token"],
    )

    res_result = (
        client.table("autorater_results")
        .select("dataset_item_id,llm_response,overall_score,result")
        .eq("autorater_run_id", run_id)
        .execute()
    )
    results_data = getattr(res_result, "data", None) or []

    if not results_data:
        typer.echo(f"No results found for run {run_id}; skipping --output.", err=True)
        return

    item_ids = [r["dataset_item_id"] for r in results_data if r.get("dataset_item_id")]
    items_result = (
        client.table("dataset_items")
        .select("id,input")
        .in_("id", item_ids)
        .execute()
    )
    items_by_id = {
        r["id"]: r.get("input") or {}
        for r in (getattr(items_result, "data", None) or [])
    }

    items_out = []
    scores: list[float] = []
    for r in results_data:
        did = r.get("dataset_item_id") or ""
        row_input = items_by_id.get(did, {})
        model_input = _dmi(row_input) if row_input else ""
        expected_output = _deo(row_input) if row_input else ""
        score_val = r.get("overall_score")
        if score_val is not None:
            scores.append(float(score_val))
        result_json = r.get("result") or {}
        reason_parts: list[str] = []
        if isinstance(result_json, dict):
            for eval_result in result_json.values():
                if isinstance(eval_result, dict):
                    for key in ("rationale", "reason", "reasoning"):
                        val = eval_result.get(key)
                        if val:
                            reason_parts.append(str(val))
                            break
        reason = "; ".join(reason_parts) if reason_parts else (f"{float(score_val):.4f}" if score_val is not None else "")
        items_out.append({
            "item_id": did,
            "model_input": model_input,
            "model_response": r.get("llm_response") or "",
            "expected_output": expected_output,
            "score": score_val,
            "reason": reason,
        })

    mean_score = sum(scores) / len(scores) if scores else 0.0
    output_data = {"mean_score": mean_score, "run_id": run_id, "items": items_out}
    Path(output_path).write_text(json.dumps(output_data, indent=2, ensure_ascii=False))
    typer.echo(f"Results written to {output_path}")


