@app.command()
def status() -> None:
    """Show current login status — reads credentials locally, no network call."""
    from zhanla_cli.auth import get_credentials, get_credentials_path

    cli_version = _installed_cli_version()

    creds_path = get_credentials_path()

    try:
        creds = get_credentials()
    except RuntimeError:
        creds = None

    if creds is None:
        typer.echo("Not logged in. Run `zhanla login` first.")
        typer.echo(f"Credentials: {creds_path}")
        return

    org_name = creds.get("org_name") or creds.get("org_id") or "unknown"
    typer.echo(f"Logged in:   {org_name}")
    typer.echo(f"CLI version: {cli_version}")
    typer.echo(f"Credentials: {creds_path}")


