# zhanla validate
# ---------------------------------------------------------------------------

@app.command()
def validate(
    target: str = typer.Argument(help="Path to component file (e.g. components.ts or components.py)"),
) -> None:
    """Validate component definitions offline — no auth or network required."""
    from zhanla_cli.manifest import validate_manifest
    from zhanla_cli.runners import detect_language, discover_ts_components, RunnerError

    try:
        lang = detect_language(target)
    except ValueError as e:
        typer.echo(str(e), err=True)
        raise typer.Exit(1)

    has_errors = False

    if lang == "typescript":
        try:
            manifests = discover_ts_components(target)
        except RunnerError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)
        except ValueError as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

        for m in manifests:
            errors = validate_manifest(m)
            comp_type = m.component_type or "unknown"
            if errors:
                has_errors = True
                typer.echo(f"✗ {m.key} ({comp_type}) — {'; '.join(errors)}")
            else:
                typer.echo(f"✓ {m.key} ({comp_type})")
    else:
        try:
            from zhanla_cli.discovery import discover_components, validate_component
        except ModuleNotFoundError as exc:
            if _is_missing_python_sdk(exc):
                _exit_missing_python_sdk()
            raise

        try:
            components = discover_components(target)
        except Exception as e:
            typer.echo(str(e), err=True)
            raise typer.Exit(1)

        for comp in components:
            errors = validate_component(comp)
            comp_type = getattr(comp.component_type, "value", str(comp.component_type))
            if errors:
                has_errors = True
                typer.echo(f"✗ {comp.key} ({comp_type}) — {'; '.join(errors)}")
            else:
                typer.echo(f"✓ {comp.key} ({comp_type})")

    if has_errors:
        raise typer.Exit(1)


