# zhanla list components
# ---------------------------------------------------------------------------

_RUNNABLE_COMPONENT_TYPES = {"agent", "orchestration", "tool", "skill"}


def _extract_models(definition: object, component_type: str) -> str:
    """Return a comma-separated string of distinct models from a component definition."""
    if not isinstance(definition, dict):
        return ""
    if component_type == "orchestration":
        nodes = []
        graph = definition.get("graph") or {}
        if isinstance(graph, dict):
            graph_nodes = graph.get("nodes") or {}
            if isinstance(graph_nodes, dict):
                nodes = list(graph_nodes.values())
            elif isinstance(graph_nodes, list):
                nodes = graph_nodes
        models: list[str] = []
        for node in nodes:
            if not isinstance(node, dict):
                continue
            data = node.get("data") or {}
            m = (data.get("model") or data.get("classifier") or "").strip()
            if m and m not in models:
                models.append(m)
        return ", ".join(models)
    m = (definition.get("model") or "").strip()
    return m


def _relative_date(dt_str: str | None) -> str:
    if not dt_str:
        return ""
    from datetime import datetime, timezone
    try:
        dt = datetime.fromisoformat(dt_str.replace("Z", "+00:00"))
        delta = datetime.now(timezone.utc) - dt
        days = delta.days
        if days == 0:
            return "today"
        if days == 1:
            return "yesterday"
        if days < 30:
            return f"{days}d ago"
        if days < 365:
            return f"{days // 30}mo ago"
        return f"{days // 365}y ago"
    except ValueError:
        return ""


@list_app.command("components")
def list_components(
    all_: bool = typer.Option(False, "--all", help="Include families with no prod version"),
    component_type: Optional[str] = typer.Option(
        None, "--component-type", "-t",
        help="Filter by type: agent, orchestration, tool, skill",
    ),
    name: Optional[str] = typer.Option(None, "--name", "-n", help="Filter by key substring"),
    verbose: bool = typer.Option(False, "--verbose", "-v", help="Show description column"),
) -> None:
    """List runnable components (agents, orchestrations, tools, skills) available for --web-config."""
    from rich.table import Table
    from zhanla_cli.writer import get_supabase_client as _get_client

    base_url = _get_base_url()
    token_data = _require_token(base_url)
    org_id = token_data["org_id"]

    client = _get_client(
        token_data["supabase_url"],
        token_data["supabase_anon_key"],
        token_data["access_token"],
    )

    query = (
        client.table("component_families")
        .select("id,key,component_type,created_at")
        .eq("organization_id", org_id)
        .in_("component_type", list(_RUNNABLE_COMPONENT_TYPES))
        .order("created_at", desc=True)
    )
    if component_type:
        if component_type not in _RUNNABLE_COMPONENT_TYPES:
            typer.echo(
                f"Invalid --component-type '{component_type}'. "
                f"Choose from: {', '.join(sorted(_RUNNABLE_COMPONENT_TYPES))}",
                err=True,
            )
            raise typer.Exit(1)
        query = query.eq("component_type", component_type)
    if name:
        query = query.ilike("key", f"%{name}%")

    family_rows = getattr(query.execute(), "data", None) or []

    if not family_rows:
        typer.echo("No components found.")
        return

    family_ids = [r["id"] for r in family_rows]
    prod_result = (
        client.table("component_definitions")
        .select("family_id,version,description,definition,promoted_at")
        .in_("family_id", family_ids)
        .eq("is_prod", True)
        .execute()
    )
    prod_by_family: dict[str, dict] = {}
    for r in (getattr(prod_result, "data", None) or []):
        fid = r.get("family_id")
        if fid:
            prod_by_family[fid] = r

    if not all_:
        family_rows = [r for r in family_rows if r["id"] in prod_by_family]

    if not family_rows:
        typer.echo("No components with a prod version found. Use --all to see all families.")
        return

    table = Table(title="Components", show_lines=False)
    table.add_column("KEY", style="green", no_wrap=True)
    table.add_column("TYPE", style="magenta")
    table.add_column("VERSION", style="cyan")
    table.add_column("MODEL", style="yellow")
    table.add_column("LAST PROMOTED", style="dim")
    if verbose:
        table.add_column("DESCRIPTION", style="white")

    for row in family_rows:
        prod = prod_by_family.get(row["id"])
        version_str = f"v{prod['version']}" if prod else "—"
        model_str = _extract_models(prod.get("definition") if prod else None, row.get("component_type") or "") if prod else ""
        promoted_str = _relative_date(prod.get("promoted_at") if prod else None)
        desc_str = (prod.get("description") or "")[:50] if prod else ""
        cells = [
            row.get("key") or "",
            row.get("component_type") or "",
            version_str,
            model_str,
            promoted_str,
        ]
        if verbose:
            cells.append(desc_str)
        table.add_row(*cells)

    console.print(table)
    console.print("[dim]Use --web-config <KEY> in `zhanla run`[/dim]")


if __name__ == "__main__":
    app()
